import { Tooltip as TooltipPrimitive } from "@base-ui/react/tooltip";
import { createStyleContext } from "@/registry/bare/lib/create-style-context";
import { createPropSplitter } from "@/registry/bare/lib/split-variant-props";
import { tooltipStyles } from "./styles";
import type { VariantProps } from "@/registry/bare/lib/tv.config";

type TooltipStyles = ReturnType<typeof tooltipStyles>;
type TooltipVariantProps = VariantProps<typeof tooltipStyles>;

const { StyleContext, useStyles } =
  createStyleContext<TooltipStyles>("Tooltip");
const splitProps = createPropSplitter(tooltipStyles);

export { useStyles as useTooltipStyles };

interface TooltipRootProps
  extends TooltipPrimitive.Root.Props,
    TooltipVariantProps {
  styles?: TooltipStyles;
}

export function TooltipRoot(props: TooltipRootProps) {
  const [variantProps, { styles, ...htmlProps }] = splitProps(
    props as Record<string, any>,
  );
  const s = styles ?? tooltipStyles(variantProps);
  return (
    <StyleContext value={s}>
      <TooltipPrimitive.Root {...htmlProps} />
    </StyleContext>
  );
}

import { Tooltip as TooltipPrimitive } from "@base-ui/react/tooltip";
import { useTooltipStyles } from "./tooltip-root";

interface TooltipTriggerProps extends TooltipPrimitive.Trigger.Props {
  className?: string;
}

export function TooltipTrigger({
  className,
  ...props
}: TooltipTriggerProps) {
  const styles = useTooltipStyles();
  return (
    <TooltipPrimitive.Trigger
      {...props}
      className={styles.trigger({ class: className })}
      data-slot="tooltip-trigger"
    />
  );
}

interface TooltipPortalProps extends TooltipPrimitive.Portal.Props {}

export function TooltipPortal(props: TooltipPortalProps) {
  return <TooltipPrimitive.Portal {...props} />;
}

interface TooltipPositionerProps extends TooltipPrimitive.Positioner.Props {
  className?: string;
}

export function TooltipPositioner({
  className,
  ...props
}: TooltipPositionerProps) {
  const styles = useTooltipStyles();
  return (
    <TooltipPrimitive.Positioner
      {...props}
      className={styles.positioner({ class: className })}
      data-slot="tooltip-positioner"
    />
  );
}

interface TooltipPopupProps extends TooltipPrimitive.Popup.Props {
  className?: string;
}

export function TooltipPopup({ className, ...props }: TooltipPopupProps) {
  const styles = useTooltipStyles();
  return (
    <TooltipPrimitive.Popup
      {...props}
      className={styles.popup({ class: className })}
      data-slot="tooltip-popup"
    />
  );
}

interface TooltipArrowProps extends TooltipPrimitive.Arrow.Props {
  className?: string;
}

export function TooltipArrow({ className, ...props }: TooltipArrowProps) {
  const styles = useTooltipStyles();
  return (
    <TooltipPrimitive.Arrow
      {...props}
      className={styles.arrow({ class: className })}
      data-slot="tooltip-arrow"
    />
  );
}

import { tv } from "@/registry/bare/lib/tv.config";

export const tooltipStyles = tv({
  slots: {
    root: [""],
    trigger: [""],
    portal: [""],
    positioner: [""],
    popup: [""],
    arrow: [""],
  },
});

export { TooltipRoot } from "./tooltip-root";
export {
  TooltipTrigger,
  TooltipPortal,
  TooltipPositioner,
  TooltipPopup,
  TooltipArrow,
} from "./tooltip-parts";

export { TooltipRoot as Tooltip } from "./tooltip-root";
export {
  TooltipTrigger,
  TooltipPortal,
  TooltipPositioner,
  TooltipPopup,
  TooltipArrow,
} from "./tooltip-parts";
export { tooltipStyles } from "./styles";
